arguments.typescript:
// @ts-ignore
const task = getRepoTask();
// @ts-ignore
const result = applyRepoChange({
  repo: task.repo,
  branch: task.branch,
  title: "Fix: Update configuration",
  description: "This PR updates the configuration to fix the reported issue."
});
return {
  repo: result.repo,
  branch: result.branch,
  changedFiles: result.changedFiles,
  prTitle: result.prTitle,
  prBody: result.prBody,
  prUrl: result.prUrl
};

const task = getRepoTask();
